/* ==============================================
🦋ui区美化结束🍃弹窗齿轮美化开始============================================== */
#toast-container > .toast {
  position: relative;
  overflow: visible !important;
}
/*————弹窗————*/
/*@hr*/
#toast-container > .toast {
    background-image: none !important;
    background-color: rgba(255, 255, 255, 1) !important;/* 背景颜色 */
    border: 0px solid rgba(255, 255, 255, 1);
    border-radius: 0px ;
    box-shadow: 
    inset -3px -3px 5px rgba(140, 140, 140, 0),
    2px 2px 7px rgba(140, 140, 140, 0.3);
    opacity: 1 !important;    /* 设置透明度 */
    padding: 10px 15px 10px 50px; /* 调整内边距，上-右-下-左 */
    min-height: 30px;/* 通知框最小高度 */ 
    max-width: 260px;/* 通知框最大宽度 */

}
.toast::before {
    content: '';
    position: absolute;
    left: 4px;/* 设置图标距离左边的位置 */
    top: 50%;/* 垂直居中对齐 */
    transform: translateY(-50%);
    width: 40px;/* 宽度 */
    height: 40px;/* 高度 */
    background-size: contain;
    background-repeat: no-repeat;
    background-position: center;
}

/* 成功 (Success) 通知的自定义图标 */
.toast-success::before {
    background-image: url("data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=");
}

/* 错误 (Error) 通知的自定义图标 */
.toast-error::before {
    background-image: url("data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=");
}

/* 信息 (Info) 通知的自定义图标 */
.toast-info::before {
    background-image: url("data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=");
}

/* 警告 (Warning) 通知的自定义图标 */
.toast-warning::before {
    background-image: url("data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=");
}

/* 消息文字样式 */
.toast-title {
    color: #B7B7B7;
    font-size: 12px;
}

.toast-message {
    color: #B7B7B7 !important ;
    font-size: 12px !important ;
} 
/*————加载齿轮————*/

#load-spinner {
    background: url("data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=") no-repeat center center;
    background-size: contain;

    animation: float 3s ease-in-out infinite; 
}

/* 动画 */
@keyframes float {
    0%, 100% {
        transform: translateY(0); /* 起始和结束位置 */
    }
    50% {
        transform: translateY(-25px); /* 向上浮动 */
    }
}

/* 隐藏原图标 */
#load-spinner::before,
#load-spinner::after {
    display: none;
}
